@dataclass(kw_only=True)
class AssistantClientMessage:
    type: str
    data: Any = None

    @classmethod
    def from_value(cls, value: object, path: str = "AssistantClientMessage") -> "AssistantClientMessage":
        if isinstance(value, cls):
            return value
        if not isinstance(value, Mapping):
            raise TypeError(f"{path}: expected object")
        return cls(type=_decode_str(value.get("type", ""), _field_path(path, "type")), data=value.get("data"))

    def to_mapping(self) -> dict[str, Any]:
        return {"type": self.type, "data": _api_to_json(self.data)}


class AssistantClientMessageVariants:
    @staticmethod
    def input(data: AssistantInput) -> AssistantClientMessage:
        return AssistantClientMessage(type="input", data=_api_to_json(data))

    @staticmethod
    def cancel(data: AssistantCancel) -> AssistantClientMessage:
        return AssistantClientMessage(type="cancel", data=_api_to_json(data))


@dataclass(kw_only=True)
class AssistantClientMessageHandlers(Generic[R]):
    input: Callable[[AssistantInput, AssistantClientMessage], R]
    cancel: Callable[[AssistantCancel, AssistantClientMessage], R]


class AssistantClientMessageDispatchError(Exception):
    def __init__(self, kind: str = "unknown_type", raw_message: AssistantClientMessage | None = None):
        message_type = "" if raw_message is None else raw_message.type
        super().__init__(f"unsupported AssistantClientMessage type {message_type}")
        self.kind = kind
        self.type = message_type
        self.raw_message = raw_message


def is_assistant_client_message_dispatch_error(error: BaseException) -> bool:
    return isinstance(error, AssistantClientMessageDispatchError)


def dispatch_assistant_client_message(
    message: AssistantClientMessage | Mapping[str, Any],
    handlers: AssistantClientMessageHandlers[R],
) -> R:
    typed_message = AssistantClientMessage.from_value(message)
    match typed_message.type:
        case "input":
            return handlers.input(
                AssistantInput.from_value(typed_message.data, _field_path("AssistantClientMessage", "data")),
                typed_message,
            )
        case "cancel":
            return handlers.cancel(
                AssistantCancel.from_value(typed_message.data, _field_path("AssistantClientMessage", "data")),
                typed_message,
            )
        case _:
            raise AssistantClientMessageDispatchError("unknown_type", typed_message)
